module top_module (
    input clk,
    input reset_n,
    input d,
    output q,
    output q_bar);reg unused_q_reg;

always @(posedge clk or negedge reset_n) begin
    if (~reset_n)
        unused_q_reg <= 1'b0;
    else
        unused_q_reg <= d;
end

assign q = unused_q_reg;
assign q_bar = ~unused_q_reg;

endmodule
